// ==============================================
// PASTE YOUR ONBOARDING TRANSCRIPT BELOW
// ==============================================

const transcript = `
[PASTE YOUR COMPLETE ONBOARDING TRANSCRIPT HERE]
`;

// ==============================================
// PASTE V1 ACCOUNT MEMO (from Workflow A output)
// ==============================================

const v1AccountMemo = {
  // PASTE THE account_memo_v1 JSON HERE
};

// ==============================================
// PASTE V1 AGENT SPEC (from Workflow A output)
// ==============================================

const v1AgentSpec = {
  // PASTE THE agent_spec_v1 JSON HERE
};

return {
  json: {
    transcript: transcript,
    v1AccountMemo: v1AccountMemo,
    v1AgentSpec: v1AgentSpec
  }
};

const fs = require('fs');
const transcript = $input.first().json.transcript;
const truncated = transcript.substring(0, 12000);

// Load prompts from files
const systemMsg = fs.readFileSync('/data/prompts/groq_onboarding_system.txt', 'utf8');
let userMsg = fs.readFileSync('/data/prompts/groq_onboarding_user.txt', 'utf8');

// Replace placeholder with actual transcript
userMsg = userMsg.replace('{{TRANSCRIPT}}', truncated);

const requestBody = {
  model: "llama-3.1-8b-instant",
  messages: [
    { role: "system", content: systemMsg },
    { role: "user", content: userMsg }
  ],
  temperature: 0.1,
  max_tokens: 2000
};

return {
  json: {
    requestBody: requestBody,
    v1AccountMemo: $input.first().json.v1AccountMemo,
    v1AgentSpec: $input.first().json.v1AgentSpec
  }
};

const v1Memo = $('Prepare Groq Request').first().json.v1AccountMemo;
const v1Spec = $('Prepare Groq Request').first().json.v1AgentSpec;
const resp = $input.first().json;

let content = resp.choices[0].message.content.trim();

// Clean JSON
if (content.startsWith('```json')) content = content.slice(7);
if (content.startsWith('```')) content = content.slice(3);
if (content.endsWith('```')) content = content.slice(0, -3);
content = content.trim();

let onb;
try {
  onb = JSON.parse(content);
} catch (e) {
  return { json: { error: 'JSON parse failed', raw: content.substring(0, 500) } };
}

// Helper to clean "null" strings
const cleanNull = (val) => {
  if (val === null || val === undefined) return null;
  if (typeof val === 'string') {
    const lower = val.toLowerCase().trim();
    if (
      lower === 'null' || 
      lower === 'string or null' || 
      lower === '' || 
      lower === 'n/a' ||
      lower === 'not mentioned' ||
      lower === 'unknown' ||
      lower.includes('or null')
    ) {
      return null;
    }
  }
  return val;
};

// ====================================
// MERGE V1 + ONBOARDING -> V2
// ====================================

const v2Memo = JSON.parse(JSON.stringify(v1Memo));

// Update business hours if provided
if (onb.business_hours?.start && cleanNull(onb.business_hours.start)) {
  v2Memo.business_hours.start = onb.business_hours.start;
}
if (onb.business_hours?.end && cleanNull(onb.business_hours.end)) {
  v2Memo.business_hours.end = onb.business_hours.end;
}

// Update pricing if provided
if (cleanNull(onb.pricing?.service_call_fee)) {
  v2Memo.pricing.service_call_fee = onb.pricing.service_call_fee;
}
if (cleanNull(onb.pricing?.hourly_rate)) {
  v2Memo.pricing.hourly_rate = onb.pricing.hourly_rate;
}
if (cleanNull(onb.pricing?.disclosure_policy)) {
  v2Memo.pricing.disclose_policy = onb.pricing.disclosure_policy;
}

// Add emergency contacts if provided
if (onb.emergency_contacts && onb.emergency_contacts.length > 0) {
  const validContacts = onb.emergency_contacts.filter(c => 
    cleanNull(c.company_name) || cleanNull(c.contact_name) || cleanNull(c.phone)
  );

  if (validContacts.length > 0) {
    v2Memo.emergency_routing_rules.primary_contact = validContacts[0];
    v2Memo.emergency_routing_rules.after_hours_emergency_only_for = 
      validContacts.map(c => cleanNull(c.company_name)).filter(Boolean);
    v2Memo.emergency_definition = 
      validContacts.map(c => `Emergency calls from ${c.company_name}`);
  }
}

// Update notifications if provided
if (cleanNull(onb.notifications?.email)) {
  v2Memo.email = onb.notifications.email;
}
if (cleanNull(onb.notifications?.sms_number)) {
  v2Memo.phone = onb.notifications.sms_number;
}

// Update technical setup if provided
if (onb.technical_setup) {
  v2Memo.technical_setup = {
    phone_type: cleanNull(onb.technical_setup.phone_type),
    call_forwarding: cleanNull(onb.technical_setup.call_forwarding),
    has_second_number: onb.technical_setup.has_second_number,
    transfer_enabled: onb.technical_setup.transfer_enabled
  };

  if (onb.technical_setup.transfer_enabled === true) {
    v2Memo.call_transfer_rules.transfer_enabled = true;
  }
}

// Update after hours policy if provided
if (cleanNull(onb.after_hours_policy)) {
  v2Memo.non_emergency_routing_rules.after_hours = onb.after_hours_policy;
}

// Add special rules if provided
if (onb.special_rules && onb.special_rules.length > 0) {
  v2Memo.special_handling_rules = onb.special_rules.filter(r => cleanNull(r));
}

// Update questions/unknowns if provided
if (onb.questions_or_unknowns && onb.questions_or_unknowns.length > 0) {
  v2Memo.questions_or_unknowns = onb.questions_or_unknowns.filter(q => cleanNull(q));
}

// Update metadata
v2Memo._metadata = {
  version: "v2",
  created_at: v1Memo._metadata?.created_at,
  updated_at: new Date().toISOString(),
  sources: ["demo_call", "onboarding_call"]
};

// ====================================
// GENERATE CHANGELOG
// ====================================

const changes = [];

if (cleanNull(onb.pricing?.service_call_fee)) {
  changes.push({
    field: "pricing.service_call_fee",
    old_value: v1Memo.pricing?.service_call_fee,
    new_value: onb.pricing.service_call_fee,
    change_type: v1Memo.pricing?.service_call_fee ? "updated" : "added"
  });
}

if (cleanNull(onb.pricing?.hourly_rate)) {
  changes.push({
    field: "pricing.hourly_rate",
    old_value: v1Memo.pricing?.hourly_rate,
    new_value: onb.pricing.hourly_rate,
    change_type: v1Memo.pricing?.hourly_rate ? "updated" : "added"
  });
}

if (cleanNull(onb.business_hours?.start)) {
  changes.push({
    field: "business_hours",
    old_value: `${v1Memo.business_hours?.start} - ${v1Memo.business_hours?.end}`,
    new_value: `${onb.business_hours.start} - ${onb.business_hours.end}`,
    change_type: "updated"
  });
}

if (onb.emergency_contacts && onb.emergency_contacts.length > 0) {
  const validContacts = onb.emergency_contacts.filter(c => cleanNull(c.company_name));
  if (validContacts.length > 0) {
    changes.push({
      field: "emergency_contacts",
      old_value: null,
      new_value: validContacts,
      change_type: "added"
    });
  }
}

if (onb.technical_setup?.phone_type && cleanNull(onb.technical_setup.phone_type)) {
  changes.push({
    field: "technical_setup",
    old_value: null,
    new_value: onb.technical_setup,
    change_type: "added"
  });
}

if (cleanNull(onb.notifications?.email)) {
  changes.push({
    field: "notifications.email",
    old_value: v1Memo.email,
    new_value: onb.notifications.email,
    change_type: v1Memo.email ? "updated" : "added"
  });
}

const changelog = {
  version: "v2",
  previous_version: "v1",
  generated_at: new Date().toISOString(),
  source: "onboarding_call",
  summary: `${changes.length} changes detected`,
  changes: changes,
  next_steps: (onb.next_steps || []).filter(s => cleanNull(s)),
  remaining_unknowns: (onb.questions_or_unknowns || []).filter(q => cleanNull(q))
};

return {
  json: {
    v1Memo: v1Memo,
    v2Memo: v2Memo,
    v1Spec: v1Spec,
    onboardingData: onb,
    changelog: changelog
  }
};

const fs = require('fs');
const path = require('path');
const { v2Memo, v1Spec, onboardingData, changelog } = $input.first().json;

// Load template
let template = fs.readFileSync('/data/prompts/agent_system_prompt_template_v2.txt', 'utf8');

// Prepare values
const biz = v2Memo.company_name || "[Company Name]";
const owner = v2Memo.owner_name || "[Owner]";
const svcs = v2Memo.services_supported.length > 0 
  ? v2Memo.services_supported.join(", ") 
  : "[Services]";
const excl = v2Memo.services_not_supported?.join(", ") || "";
const hrs = v2Memo.business_hours;
const bizHrs = `${hrs.days.join(", ")} ${hrs.start} - ${hrs.end}`;
const fee = v2Memo.pricing?.service_call_fee || "[Not Specified]";
const rate = v2Memo.pricing?.hourly_rate || "[Not Specified]";
const pricingPolicy = v2Memo.pricing?.disclose_policy 
  ? `- Policy: ${v2Memo.pricing.disclose_policy}` 
  : "";

// Build emergency section
const emgContacts = v2Memo.emergency_routing_rules?.primary_contact 
  ? [v2Memo.emergency_routing_rules.primary_contact]
  : [];

let emgSection = "";
if (emgContacts.length > 0 && emgContacts[0].company_name) {
  const primary = emgContacts[0];
  const vipNames = v2Memo.emergency_routing_rules.after_hours_emergency_only_for?.join(", ") || primary.company_name;

  emgSection = `
## VIP/EMERGENCY CONTACTS (After Hours)
Transfer IMMEDIATELY for these callers:
- ${vipNames}

Primary Contact: ${primary.contact_name || 'Contact'} @ ${primary.phone || 'Phone on file'}
${primary.email ? `Email: ${primary.email}` : ""}
${primary.notes ? `Notes: ${primary.notes}` : ""}

After-Hours Emergency Flow for VIP:
1. Caller says they're from ${vipNames}
2. Say: "Let me get your details and connect you right away."
3. Collect: Name, phone, property address, issue description
4. Transfer to: ${primary.phone}
5. If transfer fails: "I've flagged this as urgent. Someone will call you within 1 hour."`;
}

// Replace placeholders
const systemPrompt = template
  .replace(/\{\{COMPANY_NAME\}\}/g, biz)
  .replace(/\{\{OWNER_NAME\}\}/g, owner)
  .replace(/\{\{BUSINESS_HOURS\}\}/g, bizHrs)
  .replace(/\{\{SERVICES\}\}/g, svcs)
  .replace(/\{\{EXCLUDED_SERVICES\}\}/g, excl ? `- Does NOT offer: ${excl}` : "")
  .replace(/\{\{SERVICE_FEE\}\}/g, fee)
  .replace(/\{\{HOURLY_RATE\}\}/g, rate)
  .replace(/\{\{PRICING_POLICY\}\}/g, pricingPolicy)
  .replace(/\{\{EMERGENCY_SECTION\}\}/g, emgSection);

// Build V2 agent spec
const v2Spec = JSON.parse(JSON.stringify(v1Spec));

v2Spec.response_engine.system_prompt = systemPrompt;
v2Spec.business_config.business_hours = v2Memo.business_hours;
v2Spec.business_config.pricing = v2Memo.pricing;

if (v2Memo.call_transfer_rules?.transfer_enabled) {
  v2Spec.call_handling.transfer_enabled = true;
}

// Add emergency contacts
v2Spec.special_contacts = emgContacts;

// Update notifications
if (v2Memo.email) {
  v2Spec.notifications.email = v2Memo.email;
}
if (v2Memo.phone) {
  v2Spec.notifications.sms = v2Memo.phone;
}

// Update metadata
v2Spec._metadata = {
  version: "v2",
  status: "updated",
  created_at: v1Spec._metadata?.created_at,
  updated_at: new Date().toISOString(),
  source: "onboarding_call",
  account_id: v2Memo.account_id,
  changes_from_v1: changelog.changes.length
};

// Create task
const task = {
  task_id: `TASK-${Date.now()}`,
  account_id: v2Memo.account_id,
  company_name: biz,
  task_type: "onboarding_call_processed",
  status: "complete",
  pipeline: "Pipeline B: Onboarding -> V2",
  version: "v2",
  changes_count: changelog.changes.length,
  outputs: {
    account_memo: `outputs/${v2Memo.account_id}/v2/account_memo.json`,
    agent_spec: `outputs/${v2Memo.account_id}/v2/agent_spec.json`,
    changelog: `outputs/${v2Memo.account_id}/v2/changelog.json`
  },
  created_at: new Date().toISOString(),
  created_by: "n8n_automation",
  next_action: "Agent ready for deployment"
};

// Write files
const outputDir = `/outputs/${v2Memo.account_id}/v2`;
fs.mkdirSync(outputDir, { recursive: true });
fs.writeFileSync(path.join(outputDir, 'account_memo.json'), JSON.stringify(v2Memo, null, 2));
fs.writeFileSync(path.join(outputDir, 'agent_spec.json'), JSON.stringify(v2Spec, null, 2));
fs.writeFileSync(path.join(outputDir, 'changelog.json'), JSON.stringify(changelog, null, 2));

// Update tasks.json
const tasksFile = '/outputs/tasks.json';
let tasks = { tasks: [] };
try {
  if (fs.existsSync(tasksFile)) {
    tasks = JSON.parse(fs.readFileSync(tasksFile, 'utf8'));
  }
} catch (e) {}
tasks.tasks.push(task);
fs.writeFileSync(tasksFile, JSON.stringify(tasks, null, 2));

return {
  json: {
    v2Memo: v2Memo,
    v2Spec: v2Spec,
    changelog: changelog,
    task: task,
    files_saved: [
      `${outputDir}/account_memo.json`,
      `${outputDir}/agent_spec.json`,
      `${outputDir}/changelog.json`,
      tasksFile
    ]
  }
};

const { v2Memo, v2Spec, changelog, task, files_saved } = $input.first().json;

return {
  json: {
    success: true,
    message: "Pipeline B Complete - V2 Files Saved!",
    company_name: v2Memo.company_name,
    account_id: v2Memo.account_id,
    changes_detected: changelog.changes.length,
    files_saved: files_saved,
    account_memo_v2: v2Memo,
    agent_spec_v2: v2Spec,
    changelog: changelog,
    task: task
  }
};
